import _ from 'lodash';

import { RESOURCE_STATUSES } from '@/constants/app.constants';

import { Ball } from './ball';
import { BallPosition } from './ball-position';
import { BaseModel, CastableTypes } from './base-model';
import { Session } from './session';
import { TeamPlan } from './team-plan';

export class Resource extends BaseModel {
  static _cast: Partial<Record<keyof Resource, CastableTypes>> = {
    createdAt: 'date',
    updatedAt: 'date',
  };

  id!: string;
  userId: string | null = null;
  playerId!: number;
  sessionId!: string;
  teamPlanId: string | null = null;

  accX: number | null = null;
  accY: number | null = null;
  accZ: number | null = null;
  algorithmVersion: string | null = null;
  analysisTime: number | null = null;
  analyzeType: number | null = null;
  appVersion: string | null = null;
  cameraMode: string | null = null;
  device: string | null = null;
  focalLength: number | null = null;
  focus: number | null = null;
  fps: number | null = null;
  isAutoFocus: boolean | null = null;
  iso: number | null = null;
  lens: string | null = null;
  longsideAngleOfView: number | null = null;
  movieHeight: number | null = null;
  movieTime: number | null = null;
  movieWidth: number | null = null;
  originalVideoFilename: string | null = null;
  recordedAt: string | null = null;
  shutterSpeed: number | null = null;
  status!: number;
  uploadFilename!: string;
  zoom: number | null = null;

  presignedOriginalVideoUrl: string | null = null;

  createdAt!: string;
  updatedAt!: string;
  deleteFlag!: boolean;

  session: Session | null = null;

  teamPlan: TeamPlan | null = null;

  ballInfoList: {
    ball: Ball;
    positions: BallPosition[];
  }[] = [];

  deletedBalls: Ball[] = [];

  constructor(data?: any) {
    super();
    this.init(Resource, data);
    this.session = Session.newInstance(Session, data?.session);
    this.deletedBalls = Ball.newInstances(Ball, data.deletedBalls);
    this.teamPlan = TeamPlan.newInstance(TeamPlan, data?.teamPlan);
    this.ballInfoList = (data?.ballInfoList ?? []).map((info: any) => {
      return {
        ball: Ball.newInstance(Ball, info.ball),
        positions: BallPosition.newInstances(BallPosition, info.positions),
      };
    });
  }

  get canDelete() {
    return (
      !RESOURCE_STATUSES.in_queue.value.includes(this.status) &&
      !RESOURCE_STATUSES.processing.value.includes(this.status)
    );
  }

  get canReanalyze() {
    return (
      RESOURCE_STATUSES.error.value.includes(this.status) ||
      // NOTE: Even if analysis fails due to insufficient balls, there is room
      // for reanalysis if the available ball count has been restored through
      // contract renewal or item purchases.
      RESOURCE_STATUSES.insufficient_balls.value.includes(this.status)
    );
  }
}

// NOTE: These are function overloads, so we need to disable the eslint rules.
hasBasicWriteAccessFor<T extends RecordWithUserIdAndTeamId>(
  record: T,
): boolean;
// eslint-disable-next-line no-dupe-class-members
