// eslint-disable-next-line no-dupe-class-members
hasBasicWriteAccessFor<T extends RecordWithUserIdAndTeamId>(
  record: T,
  teamId?: string,
) {
  const canWriteAcrossTeam = User.isAccessible(
    this,
    teamId ?? record.teamId,
    'basic',
    'write',
    true,
  );
  const canWriteToOwnRecord = User.isAccessible(
    this,
    teamId ?? record.teamId,
    'basic',
    'write',
    false,
  );
  const isRecordOwner = record.userId !== null && record.userId === this.id;

  return canWriteAcrossTeam || (isRecordOwner && canWriteToOwnRecord);
}

